import React, { useEffect, useState } from 'react';
import fileService from '../services/fileService';
import { useNavigate } from 'react-router-dom';
function Dashboard(){
  const [file,setFile]=useState(null); const [files,setFiles]=useState([]);
  const navigate=useNavigate();
  const fetch = async()=>{ try{ const res = await fileService.getMyFiles(); setFiles(res); }catch(e){ console.error(e); } };
  useEffect(()=>{ fetch(); },[]);
  const upload=async(e)=>{ e.preventDefault(); if(!file) return alert('Select file'); try{ await fileService.uploadFile(file); alert('Uploaded'); fetch(); }catch(e){ alert('Upload failed'); } };
  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold mb-4">Dashboard</h2>
      <form onSubmit={upload} className="flex gap-3 mb-6">
        <input type="file" onChange={e=>setFile(e.target.files[0])} />
        <button className="bg-blue-600 text-white px-4 py-2 rounded">Upload</button>
      </form>
      <div>
        <h3 className="font-semibold mb-2">My Files</h3>
        <table className="w-full bg-white">
          <thead><tr><th>ID</th><th>Name</th><th>Uploaded</th><th>Actions</th></tr></thead>
          <tbody>{files.map(f=>(
            <tr key={f.id} className="border-t">
              <td className="p-2">{f.id}</td>
              <td className="p-2">{f.originalname}</td>
              <td className="p-2">{new Date(f.uploaded_at).toLocaleString()}</td>
              <td className="p-2">
                <button onClick={()=>navigate('/grant-access/'+f.id)} className="bg-green-500 text-white px-2 py-1 rounded mr-2">Grant</button>
                <button onClick={async()=>{ await fileService.deleteFile(f.id); fetch(); }} className="bg-red-500 text-white px-2 py-1 rounded">Delete</button>
              </td>
            </tr>
          ))}</tbody>
        </table>
      </div>
    </div>
  );
}
export default Dashboard;
